  ('judicial-57f41407-moex-00672', 'judicial-57f41407', 'judicial-57f41407-moex-111-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲涉犯竊盜罪，被檢察官提起公訴，對於法官之迴避。依刑事訴訟法，下列敘述何者正確？', '["甲以法官有應自行迴避之事由，而不自行迴避為由聲請迴避時，應由法官所屬之法院以合議裁定", "甲之輔佐人認為法官有自行迴避之事由，而不自行迴避時，得聲請法官迴避", "甲已就案件陳述，並足以表明受法官裁判後，得以法官執行職務有偏頗之虞為理由聲請迴避", "僅限於第一審辯論終結前，甲始可聲請法官迴避"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "5d332bd012e0", "answer_pdf_sha1": "18f2ff40e370", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
